using UnityEngine;

/// <summary>
/// Contrato comum a todas as abas do Menu Secundário ("-").
///
/// O <see cref="SecondaryMenuController"/> mantém uma lista ordenada de abas,
/// activa apenas a seleccionada e chama <see cref="Refresh"/> sempre que o
/// menu abre ou o jogador navega com L/R entre abas.
///
/// Para adicionar uma nova aba:
/// 1. Criar um MonoBehaviour que implemente esta interface.
/// 2. Arrastar o componente para "tabBehaviours" no Inspector do
///    <see cref="SecondaryMenuController"/>.
/// 3. Adicionar a label correspondente a "tabLabels".
/// </summary>
public interface ISecondaryMenuTab
{
    /// <summary>Nome da aba mostrado na barra de navegação (ex: "UPGRADES", "EMBLEMAS").</summary>
    string TabName { get; }

    /// <summary>GameObject raiz da aba — activado quando seleccionada, desactivado nas restantes.</summary>
    GameObject Root { get; }

    /// <summary>
    /// Chamado sempre que a aba passa a estar visível (abertura do menu ou
    /// navegação L/R até ela). Deve repopular o conteúdo a partir do estado
    /// actual do jogo.
    /// </summary>
    void Refresh();

    /// <summary>Chamado quando a aba deixa de estar visível (navegação para outra aba, ou fecho do menu).</summary>
    void OnHide();
}
